// UnmarshalYAML implements the yaml.Unmarshaler interface to provide backward
// compatibility for the custom_resource_config_file YAML key which was renamed
// to custom_resource_state_config_file in v2.17.0.
func (o *Options) UnmarshalYAML(value *yaml.Node) error {
	// Use a type alias to avoid infinite recursion
	type optsAlias Options
	var alias optsAlias
	if err := value.Decode(&alias); err != nil {
		return err
	}
	*o = Options(alias)

	// Backward compatibility: if the legacy field was set and the new field
	// was not, copy the legacy value to the new field.
	if o.LegacyCustomResourceConfigFile != "" && o.CustomResourceConfigFile == "" {
		o.CustomResourceConfigFile = o.LegacyCustomResourceConfigFile
	}

	return nil
}

// GetConfigFile is the getter for --config value.
func GetConfigFile(opt Options) string {
	return opt.Config
}

// NewOptions returns a new instance of `Options`.
func NewOptions() *Options {
	return &Options{
		Resources:            ResourceSet{},
		MetricAllowlist:      MetricSet{},
		MetricDenylist:       MetricSet{},
		MetricOptInList:      MetricSet{},
		AnnotationsAllowList: LabelsAllowList{},
		LabelsAllowList:      LabelsAllowList{},
	}
}

